365	func reviewResultHasACEvidence(res *ReviewResult) bool {
366		if res == nil || res.Verdict != VerdictApprove {
367			return false
368		}
369		if len(res.PerAC) == 0 {
370			return false
371		}
372		for _, ac := range res.PerAC {
373			if strings.TrimSpace(ac.Evidence) == "" {
374				return false
375			}
376		}
377		return true
378	}
