380	// applyReviewTriageDecision runs the triage policy after a BLOCK or
381	// REQUEST_CHANGES review verdict has been recorded for `beadID`. It reads
382	// prior review events to compute the BLOCK count, biases the result toward
383	// re-attempt when the latest BLOCK was paired with a degraded reviewer
384	// (kind:review-pairing-degraded), then applies the chosen action by writing
385	// metadata, labels, and a kind:triage-decision event.
386	//
387	// Errors from the underlying store are best-effort: callers continue
388	// regardless so a triage-side failure cannot strand a bead in an
389	// inconsistent review state. This callout previously lived as a method on
390	// ExecuteBeadWorker; the C3
391	// extraction (ddx-a921ff01) moves it inside the post-merge-review pipeline
392	// driven by RunPostMergeReview / try.Attempt.
393	func applyReviewTriageDecision(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, currentTier string) error {
394		events, err := store.Events(beadID)
395		if err != nil {
396			return err
397		}
398	
399		var blockTimestamps []time.Time
400		var pairingDegraded []time.Time
401		for _, ev := range events {
402			switch {
403			case ev.Kind == "review" && strings.TrimSpace(ev.Summary) == "BLOCK":
404				blockTimestamps = append(blockTimestamps, ev.CreatedAt)
405			case ev.Kind == ReviewPairingDegradedEventKind:
406				pairingDegraded = append(pairingDegraded, ev.CreatedAt)
407			}
408		}
409	
410		// History excludes the current attempt. The just-appended BLOCK (if any)
411		// is the last entry in blockTimestamps and must not be counted as prior
412		// history per triage.Decide()'s contract.
413		historyCount := len(blockTimestamps)
414		if historyCount > 0 {
415			historyCount--
416		}
417		history := make([]triage.FailureMode, 0, historyCount)
418		for i := 0; i < historyCount; i++ {
419			history = append(history, triage.FailureModeReviewBlock)
420		}
421	
422		policy := triage.DefaultPolicy()
423		action := policy.Decide(beadID, triage.FailureModeReviewBlock, history)
424	
425		pairedDegraded := latestBlockPairedDegraded(blockTimestamps, pairingDegraded)
426		if pairedDegraded && action == triage.ActionEscalateTier {
427			action = triage.ActionReAttemptWithContext
428		}
429	
430		return applyTriageAction(store, beadID, actor, now, action, currentTier, pairedDegraded)
431	}
432	
433	// latestBlockPairedDegraded reports whether the most recent BLOCK event was
434	// paired with a review-pairing-degraded event from the same attempt window
435	// (between the previous BLOCK and this one).
436	func latestBlockPairedDegraded(blocks, pairing []time.Time) bool {
437		if len(blocks) == 0 || len(pairing) == 0 {
438			return false
439		}
440		latest := blocks[len(blocks)-1]
441		var prev time.Time
442		if len(blocks) >= 2 {
443			prev = blocks[len(blocks)-2]
444		}
445		for _, t := range pairing {
446			if t.After(prev) && !t.After(latest) {
447				return true
448			}
449		}
450		return false
451	}
452	
453	// applyTriageAction performs the side effects for a chosen Action: writes a
454	// tier-pin hint into bead.Extra (escalate_tier), appends a needs_human label
455	// (needs_human), and always records a kind:triage-decision event.
456	func applyTriageAction(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, action triage.Action, currentTier string, pairedDegraded bool) error {
457		body := map[string]any{
458			"action": string(action),
459			"mode":   string(triage.FailureModeReviewBlock),
460		}
461		if pairedDegraded {
462			body["pairing_degraded"] = true
463		}
464	
465		switch action {
466		case triage.ActionEscalateTier:
467			nextTier := nextEscalatedTier(currentTier)
468			body["tier_hint"] = string(nextTier)
469			_ = store.Update(beadID, func(b *bead.Bead) {
470				if b.Extra == nil {
471					b.Extra = make(map[string]any)
472				}
473				b.Extra[TriageTierHintKey] = string(nextTier)
474			})
475		case triage.ActionNeedsHuman:
476			_ = store.Update(beadID, func(b *bead.Bead) {
477				if !HasBeadLabel(b.Labels, TriageNeedsHumanLabel) {
478					b.Labels = append(b.Labels, TriageNeedsHumanLabel)
479				}
480			})
481		}
482	
483		bodyJSON, _ := json.Marshal(body)
484		return store.AppendEvent(beadID, bead.BeadEvent{
485			Kind:      triageDecisionEventKind,
486			Summary:   string(triage.FailureModeReviewBlock) + ": " + string(action),
487			Body:      string(bodyJSON),
488			Actor:     actor,
489			Source:    "ddx agent execute-loop",
490			CreatedAt: now,
491		})
492	}
493	
494	// nextEscalatedTier returns the next tier above `current`. An unrecognised or
495	// empty current tier defaults to standard; smart is its own ceiling.
496	func nextEscalatedTier(current string) escalation.ModelTier {
497		switch escalation.ModelTier(current) {
498		case escalation.TierCheap:
499			return escalation.TierStandard
500		case escalation.TierStandard:
501			return escalation.TierSmart
502		case escalation.TierSmart:
503			return escalation.TierSmart
504		default:
505			return escalation.TierStandard
506		}
507	}
